const competitors = [
  "HubSpot",
  "Salesforce",
  "Zoho CRM"
];

// ✅ correct way to get all items in n8n

const items = $input.all();

return items.map(item => {

  const techName = item.json.data?.[0]?.attributes?.name || "";
  const domain = (item.json.company_domain || "").toLowerCase();

  const techLower = techName.toLowerCase();

  const isCompetitor = competitors.some(c =>
    techLower.includes(c.toLowerCase())
  );

  const isSameCompany = domain.includes(techLower);

  return {
    json: {
      ...item.json,
      techName,
      competitorDetected: isCompetitor && !isSameCompany
    }
  };
});

const items = $input.all();

return items.map((item, index) => {

  // ✅ har item ke corresponding row se renewal_date lo (index fix)
  const sheetItem = $items("Fetch Customers from Google Sheet")[index];
  const renewalDate = new Date(sheetItem.json.renewal_date);

  const today = new Date();

  const diffTime = renewalDate - today;
  const diffDays = diffTime / (1000 * 60 * 60 * 24);

  return {
    json: {
      ...item.json,
      daysToRenewal: Math.round(diffDays),
      within90Days: diffDays <= 90
    }
  };
});

